// src/components/Navbar.jsx
import React, { useState, useEffect } from 'react';
import { Navbar, Nav, Container, NavDropdown, Form, Button, Modal } from 'react-bootstrap';
import { Link, useLocation } from 'react-router-dom';
import { 
  FaHome, FaInfoCircle, FaProjectDiagram, 
  FaEnvelope, FaPhone, FaTimes, FaPaperPlane,
  FaFacebook, FaTwitter, FaInstagram, FaLinkedin,
  FaImages // Added gallery icon
} from 'react-icons/fa';
import logo from '../assets/logo.png'; // Import your logo

const Navigation = () => {
  // ... existing state and hooks remain the same ...

  return (
    <>
      {/* Modern Navbar */}
      <Navbar 
        // ... existing props remain the same ...
      >
        <Container fluid className="px-4">
          {/* ... existing brand code remains the same ... */}
          
          <Navbar.Toggle aria-controls="main-nav" className="border-0">
            {/* ... existing toggle code remains the same ... */}
          </Navbar.Toggle>
          
          <Navbar.Collapse id="main-nav">
            <Nav className="ms-auto align-items-lg-center">
              {/* ... existing Home and About links ... */}
              
              {/* Initiatives Dropdown */}
              <NavDropdown 
                // ... existing dropdown props ...
              >
                {/* ... existing dropdown items ... */}
              </NavDropdown>

              {/* NEW GALLERY BUTTON */}
              <Nav.Link as={Link} to="/gallery" className="nav-link">
                <FaImages className="me-1" /> Gallery
              </Nav.Link>
              
              {/* ... existing Contact button ... */}
              
              {/* ... existing social icons for mobile ... */}
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      {/* ... existing Contact Modal remains the same ... */}

      {/* Custom CSS - Add new style for gallery link */}
      <style jsx>{`
        /* ... existing styles ... */
        
        /* Add gallery link to match others */
        .nav-link.gallery-link {
          color: rgba(255, 255, 255, 0.85) !important;
        }
        
        .nav-link.gallery-link:hover {
          color: #88d498 !important;
        }
        
        .nav-link.gallery-link::after {
          content: '';
          position: absolute;
          bottom: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 0;
          height: 2px;
          background: #88d498;
          transition: width 0.3s ease;
        }
        
        .nav-link.gallery-link:hover::after {
          width: 70%;
        }
        
        /* ... rest of existing styles ... */
      `}</style>
    </>
  );
};

export default Navigation;
